cumprod_cuda_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

template<typename scalar_t>
__global__ void cumprod_forward_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int64_t outer_size,
    const int64_t dim_size,
    const int64_t inner_size) {

    // Defensive check: block must be 1D (only x dimension used)
    assert(blockDim.y == 1 && blockDim.z == 1 && 
           "Kernel requires 1D block configuration");

    // Robust linear thread index computation
    const int64_t thread_id = threadIdx.x + 
                              threadIdx.y * blockDim.x + 
                              threadIdx.z * blockDim.x * blockDim.y;

    const int64_t block_id = blockIdx.x + 
                             blockIdx.y * gridDim.x + 
                             blockIdx.z * gridDim.x * gridDim.y;

    const int64_t threads_per_block = blockDim.x * blockDim.y * blockDim.z;
    const int64_t total_threads = threads_per_block * gridDim.x * gridDim.y * gridDim.z;

    // Each thread handles one inner element per outer index
    for (int64_t idx = block_id * threads_per_block + thread_id; 
         idx < outer_size * inner_size; 
         idx += total_threads) {

        const int64_t outer_idx = idx / inner_size;
        const int64_t inner_idx = idx % inner_size;

        if (outer_idx >= outer_size || inner_idx >= inner_size) continue;

        const int64_t base_offset = outer_idx * dim_size * inner_size + inner_idx;
        const int64_t stride = inner_size;

        // Sequential cumulative product
        scalar_t prod = static_cast<scalar_t>(1.0);
        for (int64_t d = 0; d < dim_size; ++d) {
            scalar_t val = input[base_offset + d * stride];
            prod *= val;
            output[base_offset + d * stride] = prod;
        }
    }
}

torch::Tensor cumprod_cuda_forward(torch::Tensor input, int64_t dim) {
    // Validate input
    TORCH_CHECK(input.is_cuda(), "Input tensor must be on CUDA device");
    TORCH_CHECK(dim >= 0 && dim < input.dim(), "Invalid dimension");

    // Get tensor dimensions
    auto sizes = input.sizes();
    int64_t dim_size = sizes[dim];

    // Calculate outer and inner dimensions
    int64_t outer_size = 1;
    for (int64_t i = 0; i < dim; ++i) {
        outer_size *= sizes[i];
    }

    int64_t inner_size = 1;
    for (int64_t i = dim + 1; i < input.dim(); ++i) {
        inner_size *= sizes[i];
    }

    // Create output tensor
    auto output = torch::empty_like(input);

    // Robust launch configuration
    const int64_t total_elements = outer_size * inner_size;
    const int64_t block_size = 256;  // Fixed reasonable block size
    const int64_t grid_size = (total_elements + block_size - 1) / block_size;

    // Defensive check for launch configuration
    TORCH_CHECK(grid_size > 0 && grid_size <= 65535, 
                "Invalid grid size: " + std::to_string(grid_size));

    // Launch kernel with robust 1D configuration
    dim3 block(block_size);
    dim3 grid(grid_size);

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "cumprod_cuda_forward", ([&] {
        cumprod_forward_kernel<scalar_t><<<grid, block>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            outer_size,
            dim_size,
            inner_size
        );
    }));

    cudaError_t err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, 
                "CUDA kernel launch failed: ", cudaGetErrorString(err));

    return output;
}
